1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	const FOLLOWUP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
21	type QuoteStep = { op: "quote"; items: Item[] };
22	type Customer = { yearsWithMHPCO: number };
23	type Scenario = { customer: Customer; steps: QuoteStep[] };
24	
25	const quoteResult = (premiums: number[]) => ({ results: premiums.map((premium) => ({ premium })) });
26	
27	const sum = (numbers: number[]): number =>
28	  numbers.reduce((total, n) => total + n, 0);
29	
30	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
31	
32	const isBlockOfThreeAlike = (items: Item[]): boolean =>
33	  items.length === 3 && items.every((item) => item.type === items[0].type);
34	
35	const groupByType = (items: Item[]): Item[][] => {
36	  const groups: Record<string, Item[]> = {};
37	  for (const item of items) {
38	    (groups[item.type] ||= []).push(item);
39	  }
40	  return Object.values(groups);
41	};
42	
43	const groupBasePremium = (group: Item[]): number =>
44	  isBlockOfThreeAlike(group)
45	    ? BLOCK_OF_THREE_BASE_PREMIUM
46	    : sum(group.map(itemBasePremium));
47	
48	const itemsBasePremium = (items: Item[]): number =>
49	  sum(groupByType(items).map(groupBasePremium));
50	
51	const conditionalSurcharge = (item: Item, applies: boolean, rate: number): number =>
52	  applies ? itemBasePremium(item) * rate : 0;
53	
54	const cursedSurcharge = (item: Item): number =>
55	  conditionalSurcharge(item, item.cursed === true, CURSED_SURCHARGE_RATE);
56	
57	const highEnchantmentSurcharge = (item: Item): number =>
58	  conditionalSurcharge(
59	    item,
60	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
61	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
62	  );
63	
64	const itemSurchargesTotal = (items: Item[]): number =>
65	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
66	
67	const firstInsuranceSurcharge = (amount: number): number =>
68	  amount * FIRST_INSURANCE_SURCHARGE_RATE;
69	
70	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
71	  customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
72	    ? basePremium * LOYALTY_DISCOUNT_RATE
73	    : 0;
74	
75	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
76	  quoteIndex >= 1 ? basePremium * FOLLOWUP_DISCOUNT_RATE : 0;
77	
78	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
79	  const policyBase = itemsBasePremium(items);
80	  return Math.ceil(
81	    policyBase +
82	      itemSurchargesTotal(items) +
83	      firstInsuranceSurcharge(policyBase) -
84	      loyaltyDiscount(policyBase, customer) -
85	      followupDiscount(policyBase, quoteIndex) +
86	      PROCESSING_FEE,
87	  );
88	};
